# test_final_state.py

import os
import json
import pytest
import requests

def get_ground_truth():
    """Read the ground truth values generated by the setup script."""
    gt_path = '/tmp/ground_truth.json'
    assert os.path.exists(gt_path), "Ground truth file missing from setup."
    with open(gt_path, 'r') as f:
        return json.load(f)

def test_parquet_file_exists():
    """Verify that the cleaned parquet file has been created."""
    parquet_path = "/home/user/cleaned_sensor_data.parquet"
    assert os.path.isfile(parquet_path), f"Cleaned dataset not found at {parquet_path}"

def test_api_unauthorized_missing_token():
    """Verify the API returns 401 when no token is provided."""
    url = "http://127.0.0.1:8080/api/clean_stats"
    response = requests.get(url)
    assert response.status_code == 401, f"Expected 401 Unauthorized for missing token, got {response.status_code}"

def test_api_unauthorized_wrong_token():
    """Verify the API returns 401 when an incorrect token is provided."""
    url = "http://127.0.0.1:8080/api/clean_stats"
    headers = {"Authorization": "Bearer invalid_token_123"}
    response = requests.get(url, headers=headers)
    assert response.status_code == 401, f"Expected 401 Unauthorized for wrong token, got {response.status_code}"

def test_api_success_and_payload():
    """Verify the API returns 200 and the correct JSON payload for the valid token."""
    url = "http://127.0.0.1:8080/api/clean_stats"
    headers = {"Authorization": "Bearer sigma_clean_2024"}

    try:
        response = requests.get(url, headers=headers, timeout=5)
    except requests.exceptions.RequestException as e:
        pytest.fail(f"Failed to connect to the API: {e}")

    assert response.status_code == 200, f"Expected 200 OK, got {response.status_code}. Response: {response.text}"

    try:
        data = response.json()
    except ValueError:
        pytest.fail(f"Response is not valid JSON: {response.text}")

    expected = get_ground_truth()

    assert "retained_columns" in data, "Response JSON missing 'retained_columns' key."
    assert "max_eigenvalue" in data, "Response JSON missing 'max_eigenvalue' key."

    actual_columns = data["retained_columns"]
    expected_columns = expected["retained_columns"]
    assert sorted(actual_columns) == sorted(expected_columns), \
        f"Retained columns mismatch. Expected {expected_columns}, got {actual_columns}"

    actual_eig = data["max_eigenvalue"]
    expected_eig = expected["max_eigenvalue"]

    assert isinstance(actual_eig, (int, float)), "max_eigenvalue must be a number."
    assert abs(actual_eig - expected_eig) <= 1e-3, \
        f"max_eigenvalue mismatch. Expected ~{expected_eig}, got {actual_eig}"